import { dataToCSV } from '../utils/utils';

export interface ProjectMetric {
  'Project ID': string;
  'Metric Date': string;
  Milestone: string;
  'Completion %': number;
  'Team Morale Score': number;
  'Defect Rate': number;
  'Customer Satisfaction': number;
  'Budget Utilization %': number;
  'Resource Availability %': number;
  'Risk Level': string;
  'Stakeholder Engagement': number;
  'Training Hours': number;
  'Process Adherence %': number;
}

const MILESTONES = [
  'Project Kickoff',
  'Initial Assessment',
  'Baseline Measurement',
  'Pilot Implementation',
  'Mid-Point Review',
  'Full Rollout',
  'Post-Implementation Review',
  'Sustainability Check',
];

const RISK_LEVELS = ['Low', 'Medium', 'High', 'Critical'];

/**
 * Generates a random integer between min and max (inclusive)
 */
function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Picks a random item from an array
 */
function randomItem<T>(array: T[]): T {
  return array[Math.floor(Math.random() * array.length)];
}

/**
 * Generates a date string from a Date object
 */
function formatDate(date: Date): string {
  return date.toISOString().split('T')[0];
}

/**
 * Generates a project "personality" - a unique profile that determines
 * which metrics the project excels at and struggles with.
 * This creates more diverse and visually distinct radar chart shapes.
 */
function generateProjectPersonality(): {
  strengths: string[];
  weaknesses: string[];
  volatility: number;
} {
  const allTraits = [
    'teamMorale',
    'customerSat',
    'budgetUtil',
    'resourceAvail',
    'processAdherence',
    'stakeholderEng',
  ];

  // Shuffle and pick 2-3 strengths and 2-3 weaknesses
  const shuffled = [...allTraits].sort(() => Math.random() - 0.5);
  const numStrengths = randomInt(2, 3);
  const numWeaknesses = randomInt(2, 3);

  return {
    strengths: shuffled.slice(0, numStrengths),
    weaknesses: shuffled.slice(numStrengths, numStrengths + numWeaknesses),
    volatility: Math.random() * 0.3 + 0.1, // 0.1 to 0.4 - how much values fluctuate
  };
}

/**
 * Generates realistic metric progression based on project status
 * with high value dispersion for better radar chart visualization
 */
function generateMetricProgression(
  projectId: string,
  startDate: Date,
  endDate: Date,
  status: string
): ProjectMetric[] {
  const metrics: ProjectMetric[] = [];
  const totalDays = Math.floor((endDate.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24));
  const numberOfMetrics = Math.min(MILESTONES.length, Math.floor(totalDays / 30) + 2);

  // Determine base quality based on status
  const baseQuality = status === 'Completed' ? 0.85 : status === 'In Progress' ? 0.70 : 0.55;

  // Generate unique project personality for diverse radar shapes
  const personality = generateProjectPersonality();

  for (let i = 0; i < numberOfMetrics; i++) {
    const progressRatio = i / (numberOfMetrics - 1);
    const metricDate = new Date(
      startDate.getTime() + progressRatio * totalDays * 24 * 60 * 60 * 1000
    );

    // Helper to apply personality modifiers with wide dispersion
    const applyPersonality = (trait: string, baseValue: number): number => {
      let modifier = 0;
      if (personality.strengths.includes(trait)) {
        // Strengths get boosted significantly (add 20-40 points)
        modifier = randomInt(20, 40);
      } else if (personality.weaknesses.includes(trait)) {
        // Weaknesses get penalized significantly (subtract 25-45 points)
        modifier = -randomInt(25, 45);
      } else {
        // Neutral traits get moderate variance (-15 to +15)
        modifier = randomInt(-15, 15);
      }

      // Add volatility-based fluctuation
      const volatilitySwing = (Math.random() - 0.5) * personality.volatility * 50;

      return Math.min(100, Math.max(0, Math.round(baseValue + modifier + volatilitySwing)));
    };

    // Base values before personality is applied
    const baseCompletion = progressRatio * 100;
    const baseTeamMorale = baseQuality * 70 + 15;
    const baseCustomerSat = baseQuality * 65 + 20;
    const baseBudgetUtil = progressRatio * 60 + 20;
    const baseResourceAvail = 50 + baseQuality * 30;
    const baseProcessAdherence = baseQuality * 60 + 25;
    const baseStakeholderEng = baseQuality * 55 + 30;

    // Apply personality modifiers for dispersed values
    const completionPercent = Math.min(100, Math.round(baseCompletion + randomInt(-10, 10)));
    const teamMorale = applyPersonality('teamMorale', baseTeamMorale);
    const customerSat = applyPersonality('customerSat', baseCustomerSat);
    const budgetUtil = applyPersonality('budgetUtil', baseBudgetUtil);
    const resourceAvail = applyPersonality('resourceAvail', baseResourceAvail);
    const processAdherence = applyPersonality('processAdherence', baseProcessAdherence);
    const stakeholderEng = applyPersonality('stakeholderEng', baseStakeholderEng);

    // Defect rate inversely correlates with process adherence (with variance)
    const defectRate = Math.max(0, Math.min(100, 100 - processAdherence + randomInt(-20, 20)));

    // Training hours - more variance
    const trainingHours = randomInt(2, 60);

    // Risk level with more variance based on multiple factors
    let riskLevel: string;
    const riskScore =
      (100 - teamMorale) * 0.2 +
      (100 - processAdherence) * 0.3 +
      defectRate * 0.3 +
      (100 - resourceAvail) * 0.2;

    if (riskScore > 60) {
      riskLevel = randomItem(['High', 'Critical']);
    } else if (riskScore > 40) {
      riskLevel = randomItem(['Medium', 'High']);
    } else if (riskScore > 20) {
      riskLevel = randomItem(['Low', 'Medium']);
    } else {
      riskLevel = 'Low';
    }

    metrics.push({
      'Project ID': projectId,
      'Metric Date': formatDate(metricDate),
      Milestone: MILESTONES[i] || `Milestone ${i + 1}`,
      'Completion %': completionPercent,
      'Team Morale Score': teamMorale,
      'Defect Rate': defectRate,
      'Customer Satisfaction': customerSat,
      'Budget Utilization %': budgetUtil,
      'Resource Availability %': resourceAvail,
      'Risk Level': riskLevel,
      'Stakeholder Engagement': stakeholderEng,
      'Training Hours': trainingHours,
      'Process Adherence %': processAdherence,
    });
  }

  return metrics;
}

/**
 * Generates project metrics data that correlates with lean projects
 * @param projectsData - Array of project IDs with their start/end dates and status
 */
export function generateProjectMetrics(
  projectsData: Array<{
    projectId: string;
    startDate: string;
    endDate: string;
    status: string;
  }>
): ProjectMetric[] {
  const allMetrics: ProjectMetric[] = [];

  for (const project of projectsData) {
    const startDate = new Date(project.startDate);
    const endDate = new Date(project.endDate);

    const projectMetrics = generateMetricProgression(
      project.projectId,
      startDate,
      endDate,
      project.status
    );
    
    allMetrics.push(...projectMetrics);
  }

  return allMetrics;
}

/**
 * Generates sample metrics CSV that correlates with project data
 */
export function generateSampleMetricsCSV(
  projectsData: Array<{
    projectId: string;
    startDate: string;
    endDate: string;
    status: string;
  }>
): string {
  const metrics = generateProjectMetrics(projectsData);
  return dataToCSV(metrics);
}
