import { generateSampleProjectsCSV, LeanProject } from './sample-generator/leanProjects.generator';
import {
  generateSampleMetricsCSV,
  ProjectMetric,
} from './sample-generator/projectMetrics.generator';
import { dataToCSV, downloadCSV, fetchAndParseCSV, loadCSVFromFile, parseCSV } from './utils/utils';
import {
  analyzeProjectPerformance,
  analyzeRiskCorrelation,
  analyzeTeamEfficiency,
  analyzeBudgetTrends,
  type PerformanceAnalysis,
  type RiskAnalysis,
  type TeamEfficiencyAnalysis,
  type BudgetAnalysis,
} from './data-analysis/analysis';

// Re-export types
export type {
  LeanProject,
  ProjectMetric,
  PerformanceAnalysis,
  RiskAnalysis,
  TeamEfficiencyAnalysis,
  BudgetAnalysis,
};

// Re-export utilities
export {
  dataToCSV,
  downloadCSV,
  fetchAndParseCSV,
  generateSampleMetricsCSV,
  generateSampleProjectsCSV,
  loadCSVFromFile,
  parseCSV,
};

// Re-export analysis functions
export {
  analyzeProjectPerformance,
  analyzeRiskCorrelation,
  analyzeTeamEfficiency,
  analyzeBudgetTrends,
};

/**
 * Performs all analyses and returns results
 */
export function performAllAnalyses(projects: LeanProject[], metrics: ProjectMetric[]) {
  return {
    performance: analyzeProjectPerformance(projects, metrics),
    risk: analyzeRiskCorrelation(projects, metrics),
    teamEfficiency: analyzeTeamEfficiency(projects, metrics),
    budget: analyzeBudgetTrends(projects, metrics),
  };
}

/**
 * Performs all analyses and generates downloadable CSV files
 */
export function analyzeAndDownload(projects: LeanProject[], metrics: ProjectMetric[]): void {
  const analyses = performAllAnalyses(projects, metrics);

  // Download each analysis with a small delay
  downloadCSV(dataToCSV(analyses.performance), 'analysis-performance.csv');

  setTimeout(() => {
    downloadCSV(dataToCSV(analyses.risk), 'analysis-risk.csv');
  }, 150);

  setTimeout(() => {
    downloadCSV(dataToCSV(analyses.teamEfficiency), 'analysis-team-efficiency.csv');
  }, 300);

  setTimeout(() => {
    downloadCSV(dataToCSV(analyses.budget), 'analysis-budget-trends.csv');
  }, 450);
}
