
import type { LeanProject } from '../sample-generator/leanProjects.generator';
import type { ProjectMetric } from '../sample-generator/projectMetrics.generator';

export interface PerformanceAnalysis {
  'Project ID': string;
  'Project Name': string;
  'Overall Score': number;
  'Savings vs Target': string;
  'Quality Achievement': string;
  'Timeline Performance': string;
  'Team Morale Trend': string;
  'Recommendation': string;
}

export interface RiskAnalysis {
  'Project ID': string;
  'Project Name': string;
  'Current Risk Level': string;
  'Risk Trend': string;
  'Defect Rate Correlation': number;
  'Budget Risk': string;
  'Mitigation Priority': string;
}

export interface TeamEfficiencyAnalysis {
  'Project ID': string;
  'Project Name': string;
  'Team Size': number;
  'Avg Morale Score': number;
  'Training Hours per Person': number;
  'Process Adherence': number;
  'Efficiency Rating': string;
  'Improvement Areas': string;
}

export interface BudgetAnalysis {
  'Project ID': string;
  'Project Name': string;
  'Total Savings': number;
  'Avg Budget Utilization': number;
  'ROI Estimate': string;
  'Cost Efficiency': string;
  'Financial Health': string;
}

/**
 * Analyzes overall project performance by correlating projects with metrics
 */
export function analyzeProjectPerformance(
  projects: LeanProject[],
  metrics: ProjectMetric[]
): PerformanceAnalysis[] {
  return projects.map((project) => {
    const projectMetrics = metrics.filter((m) => m['Project ID'] === project['Project ID']);

    // Calculate averages
    const avgMorale =
      projectMetrics.reduce((sum, m) => sum + m['Team Morale Score'], 0) / projectMetrics.length || 0;
    const avgCompletion =
      projectMetrics.reduce((sum, m) => sum + m['Completion %'], 0) / projectMetrics.length || 0;
    const avgCustomerSat =
      projectMetrics.reduce((sum, m) => sum + m['Customer Satisfaction'], 0) / projectMetrics.length || 0;

    // Calculate trends
    const moraleTrend = calculateTrend(projectMetrics.map((m) => m['Team Morale Score']));

    // Overall score (0-100)
    const overallScore = Math.round(
      (avgCompletion * 0.3 + avgMorale * 10 * 0.3 + avgCustomerSat * 10 * 0.2 + project['Quality Improvement (%)'] * 0.2)
    );

    // Savings performance
    const totalSavings = project['Hard Cost Savings'] + project['Soft Cost Savings'];
    const savingsVsTarget = totalSavings > 100000 ? 'Exceeds Target' : totalSavings > 50000 ? 'Meets Target' : 'Below Target';

    // Quality achievement
    const qualityAchievement =
      project['Quality Improvement (%)'] > 30 ? 'Excellent' : project['Quality Improvement (%)'] > 15 ? 'Good' : 'Needs Improvement';

    // Timeline performance
    const timelinePerf = avgCompletion > 80 ? 'On Track' : avgCompletion > 50 ? 'At Risk' : 'Delayed';

    // Recommendation
    let recommendation = '';
    if (overallScore > 80) recommendation = 'Continue current approach';
    else if (overallScore > 60) recommendation = 'Monitor closely, minor adjustments needed';
    else recommendation = 'Requires intervention and support';

    return {
      'Project ID': project['Project ID'],
      'Project Name': project['Project Name'],
      'Overall Score': overallScore,
      'Savings vs Target': savingsVsTarget,
      'Quality Achievement': qualityAchievement,
      'Timeline Performance': timelinePerf,
      'Team Morale Trend': moraleTrend,
      'Recommendation': recommendation,
    };
  });
}

/**
 * Analyzes risk factors and correlations
 */
export function analyzeRiskCorrelation(projects: LeanProject[], metrics: ProjectMetric[]): RiskAnalysis[] {
  return projects.map((project) => {
    const projectMetrics = metrics.filter((m) => m['Project ID'] === project['Project ID']);

    // Get latest risk level
    const latestMetric = projectMetrics[projectMetrics.length - 1];
    const currentRisk = latestMetric?.['Risk Level'] || 'Unknown';

    // Calculate risk trend
    const riskLevels = projectMetrics.map((m) => m['Risk Level']);
    const riskTrend = calculateRiskTrend(riskLevels);

    // Defect rate correlation
    const avgDefectRate = projectMetrics.reduce((sum, m) => sum + m['Defect Rate'], 0) / projectMetrics.length || 0;
    const defectCorrelation = Math.round((avgDefectRate / 100) * 100) / 100;

    // Budget risk
    const avgBudgetUtil = projectMetrics.reduce((sum, m) => sum + m['Budget Utilization %'], 0) / projectMetrics.length || 0;
    const budgetRisk = avgBudgetUtil > 95 ? 'High' : avgBudgetUtil > 85 ? 'Medium' : 'Low';

    // Mitigation priority
    let priority = 'Low';
    if (currentRisk === 'Critical' || budgetRisk === 'High') priority = 'Critical';
    else if (currentRisk === 'High' || budgetRisk === 'Medium') priority = 'High';
    else if (currentRisk === 'Medium') priority = 'Medium';

    return {
      'Project ID': project['Project ID'],
      'Project Name': project['Project Name'],
      'Current Risk Level': currentRisk,
      'Risk Trend': riskTrend,
      'Defect Rate Correlation': defectCorrelation,
      'Budget Risk': budgetRisk,
      'Mitigation Priority': priority,
    };
  });
}

/**
 * Analyzes team efficiency metrics
 */
export function analyzeTeamEfficiency(projects: LeanProject[], metrics: ProjectMetric[]): TeamEfficiencyAnalysis[] {
  return projects.map((project) => {
    const projectMetrics = metrics.filter((m) => m['Project ID'] === project['Project ID']);

    const avgMorale =
      projectMetrics.reduce((sum, m) => sum + m['Team Morale Score'], 0) / projectMetrics.length || 0;
    const totalTraining = projectMetrics.reduce((sum, m) => sum + m['Training Hours'], 0);
    const trainingPerPerson = Math.round(totalTraining / project['Team Size']);
    const avgAdherence =
      projectMetrics.reduce((sum, m) => sum + m['Process Adherence %'], 0) / projectMetrics.length || 0;

    // Efficiency rating
    let efficiencyRating = '';
    if (avgMorale > 8 && avgAdherence > 85) efficiencyRating = 'High Performing';
    else if (avgMorale > 6 && avgAdherence > 70) efficiencyRating = 'Effective';
    else if (avgMorale > 5 && avgAdherence > 60) efficiencyRating = 'Adequate';
    else efficiencyRating = 'Needs Support';

    // Improvement areas
    const improvements: string[] = [];
    if (avgMorale < 7) improvements.push('Team Morale');
    if (trainingPerPerson < 20) improvements.push('Training');
    if (avgAdherence < 75) improvements.push('Process Adherence');

    return {
      'Project ID': project['Project ID'],
      'Project Name': project['Project Name'],
      'Team Size': project['Team Size'],
      'Avg Morale Score': Math.round(avgMorale * 10) / 10,
      'Training Hours per Person': trainingPerPerson,
      'Process Adherence': Math.round(avgAdherence),
      'Efficiency Rating': efficiencyRating,
      'Improvement Areas': improvements.length > 0 ? improvements.join(', ') : 'None identified',
    };
  });
}

/**
 * Analyzes budget and financial trends
 */
export function analyzeBudgetTrends(projects: LeanProject[], metrics: ProjectMetric[]): BudgetAnalysis[] {
  return projects.map((project) => {
    const projectMetrics = metrics.filter((m) => m['Project ID'] === project['Project ID']);

    const totalSavings = project['Hard Cost Savings'] + project['Soft Cost Savings'];
    const avgBudgetUtil =
      projectMetrics.reduce((sum, m) => sum + m['Budget Utilization %'], 0) / projectMetrics.length || 0;

    // ROI estimate (simplified)
    const estimatedCost = (avgBudgetUtil / 100) * 50000; // Assume $50k base budget
    const roi = ((totalSavings - estimatedCost) / estimatedCost) * 100;

    // Cost efficiency
    const costEfficiency = roi > 20 ? 'High' : roi > 10 ? 'Moderate' : 'Low';

    // Financial health
    const financialHealth = totalSavings > 100000 ? 'Strong' : totalSavings > 50000 ? 'Stable' : 'Concerning';

    return {
      'Project ID': project['Project ID'],
      'Project Name': project['Project Name'],
      'Total Savings': totalSavings,
      'Avg Budget Utilization': Math.round(avgBudgetUtil * 100) / 100,
      'ROI Estimate': `${Math.round(roi * 100) / 100}%`,
      'Cost Efficiency': costEfficiency,
      'Financial Health': financialHealth,
    };
  });
}

// Helper function to calculate trend
function calculateTrend(values: number[]): string {
  if (values.length < 2) return 'Stable';
  
  const first = values[0];
  const last = values[values.length - 1];
  const diff = last - first;
  
  if (diff > 5) return 'Improving';
  if (diff < -5) return 'Declining';
  return 'Stable';
}

// Helper function to calculate risk trend
function calculateRiskTrend(riskLevels: string[]): string {
  if (riskLevels.length < 2) return 'Stable';
  
  const lastRisk = riskLevels[riskLevels.length - 1];
  const firstRisk = riskLevels[0];
  
  if (lastRisk === 'High' && firstRisk === 'Low') return 'Improving';
  if (lastRisk === 'Low' && firstRisk === 'High') return 'Declining';
  return 'Stable';
}
