import Papa from 'papaparse/papaparse.min.js';
import { LeanProject } from '../sample-generator/leanProjects.generator';

/**
 * Converts project data to CSV string using PapaParse
 */
export function dataToCSV(data: unknown[]): string {
  return Papa.unparse(data, {
    quotes: true, // Quote all fields
    header: true, // Include header row
  });
}

/**
 * Downloads CSV file in the browser with CSP-compatible fallback
 * Tries blob URL first, falls back to data URL for SharePoint compatibility
 */
export function downloadCSV(csvContent: string, filename: string = 'lean-projects.csv'): void {
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });

  try {
    // Try blob URL first (works in most environments)
    if (typeof URL !== 'undefined' && URL.createObjectURL) {
      const link = document.createElement('a');
      if (link.download !== undefined) {
        const url = URL.createObjectURL(blob);
        link.setAttribute('href', url);
        link.setAttribute('download', filename);
        link.style.visibility = 'hidden';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
        return;
      }
    }

    // Fallback to data URL (works in SharePoint but has size limits)
    const reader = new FileReader();
    reader.onload = function() {
      const link = document.createElement('a');
      link.setAttribute('href', reader.result as string);
      link.setAttribute('download', filename);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    };
    reader.readAsDataURL(blob);

  } catch (error) {
    console.error('Download failed:', error);
    // Ultimate fallback: open in new window (user can save manually)
    const dataUrl = 'data:text/csv;charset=utf-8,' + encodeURIComponent(csvContent);
    window.open(dataUrl);
  }
}

/**
 * Parses CSV string to array of objects using PapaParse
 */
export function parseCSV<T = LeanProject>(csvContent: string): Promise<T[]> {
  return new Promise((resolve, reject) => {
    Papa.parse<T>(csvContent, {
      header: true,
      dynamicTyping: true, // Auto-convert numbers
      skipEmptyLines: true,
      complete: (results) => {
        if (results.errors.length > 0) {
          console.warn('CSV parsing warnings:', results.errors);
        }
        resolve(results.data);
      },
      error: (error: Error) => {
        reject(error);
      },
    });
  });
}

/**
 * Fetches and parses CSV from URL
 */
export async function fetchAndParseCSV<T = LeanProject>(url: string): Promise<T[]> {
  try {
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`Failed to fetch CSV: ${response.statusText}`);
    }
    const csvText = await response.text();
    return await parseCSV<T>(csvText);
  } catch (error) {
    console.error('Error fetching/parsing CSV:', error);
    throw error;
  }
}
/**
 * Opens a file dialog to select and parse a CSV file from the user's computer
 * @param accept - File types to accept (default: '.csv')
 * @returns Promise that resolves with parsed CSV data
 */
export function loadCSVFromFile<T = LeanProject>(accept: string = '.csv'): Promise<T[]> {
  return new Promise((resolve, reject) => {
    // Create a hidden file input element
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = accept;
    input.style.display = 'none';

    // Handle file selection
    input.onchange = async (event: Event) => {
      const target = event.target as HTMLInputElement;
      const file = target.files?.[0];

      if (!file) {
        reject(new Error('No file selected'));
        return;
      }

      try {
        // Read the file content
        const text = await file.text();

        // Parse the CSV
        const data = await parseCSV<T>(text);

        // Clean up
        document.body.removeChild(input);

        resolve(data);
      } catch (error) {
        document.body.removeChild(input);
        reject(error);
      }
    };

    // Handle cancel
    input.oncancel = () => {
      document.body.removeChild(input);
      reject(new Error('File selection cancelled'));
    };

    // Add to DOM and trigger click
    document.body.appendChild(input);
    input.click();
  });
}

/**
 * Opens a file dialog and returns both the file info and parsed data
 * Useful when you need the filename or other file metadata
 */
export function loadCSVFromFileWithMetadata<T = LeanProject>(
  accept: string = '.csv'
): Promise<{ file: File; data: T[] }> {
  return new Promise((resolve, reject) => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = accept;
    input.style.display = 'none';

    input.onchange = async (event: Event) => {
      const target = event.target as HTMLInputElement;
      const file = target.files?.[0];

      if (!file) {
        reject(new Error('No file selected'));
        return;
      }

      try {
        const text = await file.text();
        const data = await parseCSV<T>(text);

        document.body.removeChild(input);

        resolve({ file, data });
      } catch (error) {
        document.body.removeChild(input);
        reject(error);
      }
    };

    input.oncancel = () => {
      document.body.removeChild(input);
      reject(new Error('File selection cancelled'));
    };

    document.body.appendChild(input);
    input.click();
  });
}
