import { dataToCSV } from "../utils/utils";

export interface LeanProject {
  'Project ID': string;
  'Project Name': string;
  Status: string;
  Owner: string;
  'Start Date': string;
  'End Date': string;
  'Hard Cost Savings': number;
  'Soft Cost Savings': number;
  'Cycle Time Reduction (%)': number;
  'Waste Eliminated': string;
  'Quality Improvement (%)': number;
  'Team Size': number;
  Priority: string;
}

const PROJECT_NAMES = [
  'Inventory Optimization Initiative',
  'Production Line Kaizen Event',
  'Value Stream Mapping - Order Processing',
  '5S Implementation - Warehouse',
  'Setup Time Reduction - SMED',
  'Quality at Source Implementation',
  'Pull System Design - Assembly',
  'Standard Work Documentation',
  'Cellular Manufacturing Layout',
  'TPM Pilot Program',
  'Kanban System Implementation',
  'Root Cause Analysis Workshop',
  'Visual Management Board Setup',
  'Poka-Yoke Error Proofing',
  'Gemba Walk Initiative',
];

const STATUSES = ['Completed', 'In Progress', 'Planning', 'On Hold'];

const OWNERS = [
  'Sarah Johnson',
  'Michael Chen',
  'Emily Rodriguez',
  'David Martinez',
  'Lisa Thompson',
  'James Wilson',
  'Amanda Lee',
  'Robert Brown',
  'Patricia Garcia',
  'Christopher Davis',
];

const WASTE_TYPES = [
  'Excess Inventory',
  'Motion & Waiting',
  'Overprocessing',
  'Searching & Sorting',
  'Waiting & Downtime',
  'Defects & Rework',
  'Overproduction',
  'Inconsistency',
  'Transportation & Motion',
  'Equipment Downtime',
];

const PRIORITIES = ['High', 'Medium', 'Low'];

/**
 * Generates a random date within a range
 */
function randomDate(start: Date, end: Date): string {
  const date = new Date(start.getTime() + Math.random() * (end.getTime() - start.getTime()));
  return date.toISOString().split('T')[0];
}

/**
 * Generates a random integer between min and max (inclusive)
 */
function randomInt(min: number, max: number): number {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

/**
 * Picks a random item from an array
 */
function randomItem<T>(array: T[]): T {
  return array[Math.floor(Math.random() * array.length)];
}

/**
 * Generates sample lean project data
 */
export function generateSampleProjects(count: number): LeanProject[] {
  const projects: LeanProject[] = [];
  const startYear = new Date('2023-01-01');
  const endYear = new Date('2024-12-31');

  for (let i = 0; i < count; i++) {
    const projectId = `LEAN-${String(i + 1).padStart(3, '0')}`;
    const projectName = randomItem(PROJECT_NAMES);
    const status = randomItem(STATUSES);
    const owner = randomItem(OWNERS);

    const startDate = randomDate(startYear, new Date('2024-06-01'));
    const endDateObj = new Date(startDate);
    endDateObj.setMonth(endDateObj.getMonth() + randomInt(2, 8));
    const endDate = endDateObj.toISOString().split('T')[0];

    const hardCostSavings = status === 'Planning' ? 0 : randomInt(0, 150000);
    const softCostSavings = randomInt(0, 90000);
    const cycleTimeReduction = randomInt(10, 60);
    const wasteEliminated = randomItem(WASTE_TYPES);
    const qualityImprovement = randomInt(5, 50);
    const teamSize = randomInt(3, 12);
    const priority = randomItem(PRIORITIES);

    projects.push({
      'Project ID': projectId,
      'Project Name': projectName,
      Status: status,
      Owner: owner,
      'Start Date': startDate,
      'End Date': endDate,
      'Hard Cost Savings': hardCostSavings,
      'Soft Cost Savings': softCostSavings,
      'Cycle Time Reduction (%)': cycleTimeReduction,
      'Waste Eliminated': wasteEliminated,
      'Quality Improvement (%)': qualityImprovement,
      'Team Size': teamSize,
      Priority: priority,
    });
  }

  return projects;
}

/**
 * Generates sample CSV with n rows
 */
export function generateSampleProjectsCSV(rowCount: number): string {
  const projects = generateSampleProjects(rowCount);
  return dataToCSV(projects);
}
